import{_ as d,o as t,c as o,a0 as c}from"./chunks/framework.CWk8AOcY.js";const _=JSON.parse('{"title":"控制面配置文件路径与说明","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ops-manual/02-control-plane-config.md","filePath":"zh/guide/ops-manual/02-control-plane-config.md"}'),a={name:"guide/ops-manual/02-control-plane-config.md"};function l(i,e,r,s,n,h){return t(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="控制面配置文件路径与说明" tabindex="-1">控制面配置文件路径与说明 <a class="header-anchor" href="#控制面配置文件路径与说明" aria-label="Permalink to &quot;控制面配置文件路径与说明&quot;">​</a></h1><p>本章覆盖 one-click 控制节点上真正需要维护的控制面配置：</p><ul><li>全局环境：<code>.one-click.env</code></li><li><code>CubeMaster/conf.yaml</code></li><li><code>CubeAPI</code> 的 env / flag 配置</li><li>support（MySQL/Redis）compose</li><li><code>CubeProxy</code> / <code>CoreDNS</code> / <code>WebUI</code> 的生成配置</li></ul><h2 id="_1-one-click-全局环境文件" tabindex="-1">1. one-click 全局环境文件 <a class="header-anchor" href="#_1-one-click-全局环境文件" aria-label="Permalink to &quot;1. one-click 全局环境文件&quot;">​</a></h2><h3 id="_1-1-源文件与安装后路径" tabindex="-1">1.1 源文件与安装后路径 <a class="header-anchor" href="#_1-1-源文件与安装后路径" aria-label="Permalink to &quot;1.1 源文件与安装后路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>路径</th><th>作用</th></tr></thead><tbody><tr><td>仓库模板</td><td><code>deploy/one-click/env.example</code></td><td>打包前/安装前填写</td></tr><tr><td>安装后生效文件</td><td><code>/usr/local/services/cubetoolbox/.one-click.env</code></td><td>one-click 运行脚本统一读取</td></tr></tbody></table><p><code>install.sh</code> 会把安装前 <code>.env</code> 复制并规范化为 <code>.one-click.env</code>，再由 <code>scripts/one-click/common.sh</code> 统一加载。</p><h3 id="_1-2-关键变量分组" tabindex="-1">1.2 关键变量分组 <a class="header-anchor" href="#_1-2-关键变量分组" aria-label="Permalink to &quot;1.2 关键变量分组&quot;">​</a></h3><h4 id="部署角色与安装路径" tabindex="-1">部署角色与安装路径 <a class="header-anchor" href="#部署角色与安装路径" aria-label="Permalink to &quot;部署角色与安装路径&quot;">​</a></h4><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>ONE_CLICK_INSTALL_PREFIX</code></td><td><code>/usr/local/services/cubetoolbox</code></td><td>安装根目录</td></tr><tr><td><code>ONE_CLICK_DEPLOY_ROLE</code></td><td><code>control</code></td><td><code>control</code> 或 <code>compute</code></td></tr><tr><td><code>ONE_CLICK_RUN_QUICKCHECK</code></td><td><code>1</code></td><td>安装完成后是否跑 quickcheck</td></tr></tbody></table><h4 id="依赖容器与凭据" tabindex="-1">依赖容器与凭据 <a class="header-anchor" href="#依赖容器与凭据" aria-label="Permalink to &quot;依赖容器与凭据&quot;">​</a></h4><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>CUBE_SANDBOX_MYSQL_PORT</code></td><td><code>3306</code></td><td>MySQL 端口</td></tr><tr><td><code>CUBE_SANDBOX_REDIS_PORT</code></td><td><code>6379</code></td><td>Redis 端口</td></tr><tr><td><code>CUBE_SANDBOX_REDIS_PASSWORD</code></td><td><code>ceuhvu123</code></td><td>Redis 密码</td></tr><tr><td><code>CUBE_SANDBOX_MYSQL_DB</code></td><td><code>cube_mvp</code></td><td>数据库名</td></tr><tr><td><code>CUBE_SANDBOX_MYSQL_USER</code></td><td><code>cube</code></td><td>业务用户名</td></tr><tr><td><code>CUBE_SANDBOX_MYSQL_PASSWORD</code></td><td><code>cube_pass</code></td><td>业务密码</td></tr></tbody></table><h4 id="代理-dns-webui" tabindex="-1">代理 / DNS / WebUI <a class="header-anchor" href="#代理-dns-webui" aria-label="Permalink to &quot;代理 / DNS / WebUI&quot;">​</a></h4><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>CUBE_PROXY_ENABLE</code></td><td><code>1</code></td><td>one-click 中必须开启</td></tr><tr><td><code>CUBE_PROXY_DNS_ENABLE</code></td><td><code>1</code></td><td>one-click 中必须开启</td></tr><tr><td><code>CUBE_PROXY_HOST_PORT</code></td><td><code>443</code></td><td>HTTPS 对外端口</td></tr><tr><td><code>CUBE_PROXY_CERT_DIR</code></td><td><code>${ONE_CLICK_INSTALL_PREFIX}/cubeproxy/certs</code></td><td>证书目录</td></tr><tr><td><code>CUBE_PROXY_DNS_ANSWER_IP</code></td><td><code>${CUBE_SANDBOX_NODE_IP}</code></td><td><code>cube.app</code> 解析回包 IP</td></tr><tr><td><code>WEB_UI_ENABLE</code></td><td><code>1</code></td><td>是否启用 Dashboard</td></tr><tr><td><code>WEB_UI_HOST_PORT</code></td><td><code>12088</code></td><td>Dashboard 宿主机端口</td></tr><tr><td><code>WEB_UI_UPSTREAM</code></td><td><code>http://host.docker.internal:3000</code></td><td>WebUI nginx 反代到 CubeAPI</td></tr></tbody></table><h4 id="cubeapi-cubemaster" tabindex="-1">CubeAPI / Cubemaster <a class="header-anchor" href="#cubeapi-cubemaster" aria-label="Permalink to &quot;CubeAPI / Cubemaster&quot;">​</a></h4><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>CUBEMASTER_ADDR</code></td><td><code>127.0.0.1:8089</code></td><td>quickcheck / 内部脚本访问地址</td></tr><tr><td><code>CUBE_API_BIND</code></td><td><code>0.0.0.0:3000</code></td><td>CubeAPI 监听地址</td></tr><tr><td><code>CUBE_API_HEALTH_ADDR</code></td><td><code>127.0.0.1:3000</code></td><td>本机健康检查地址</td></tr><tr><td><code>CUBE_API_SANDBOX_DOMAIN</code></td><td><code>cube.app</code></td><td>API 返回的 sandbox 域名</td></tr><tr><td><code>AUTH_CALLBACK_URL</code></td><td>空</td><td>可选鉴权回调</td></tr></tbody></table><h2 id="_2-cubemaster-配置" tabindex="-1">2. CubeMaster 配置 <a class="header-anchor" href="#_2-cubemaster-配置" aria-label="Permalink to &quot;2. CubeMaster 配置&quot;">​</a></h2><h3 id="_2-1-路径" tabindex="-1">2.1 路径 <a class="header-anchor" href="#_2-1-路径" aria-label="Permalink to &quot;2.1 路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>路径</th></tr></thead><tbody><tr><td>仓库内模板</td><td><code>configs/single-node/cubemaster.yaml</code></td></tr><tr><td>安装后生效</td><td><code>/usr/local/services/cubetoolbox/CubeMaster/conf.yaml</code></td></tr><tr><td>进程读取方式</td><td>通过环境变量 <code>CUBE_MASTER_CONFIG_PATH</code> 指向该文件</td></tr></tbody></table><p><code>up.sh</code> 会显式导出：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CUBE_MASTER_CONFIG_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/usr/local/services/cubetoolbox/CubeMaster/conf.yaml&quot;</span></span></code></pre></div><h3 id="_2-2-主要配置段说明" tabindex="-1">2.2 主要配置段说明 <a class="header-anchor" href="#_2-2-主要配置段说明" aria-label="Permalink to &quot;2.2 主要配置段说明&quot;">​</a></h3><h4 id="common" tabindex="-1"><code>common</code> <a class="header-anchor" href="#common" aria-label="Permalink to &quot;`common`&quot;">​</a></h4><p>控制 Cubemaster 自身的 HTTP 监听与调度周期：</p><ul><li><code>http_port</code>: 控制面端口，默认 <code>8089</code></li><li><code>sync_meta_data_interval</code>: 同步元数据周期</li><li><code>sync_metric_data_interval</code>: 同步指标周期</li><li><code>collect_metric_interval</code>: 指标采集周期</li></ul><h4 id="log" tabindex="-1"><code>log</code> <a class="header-anchor" href="#log" aria-label="Permalink to &quot;`log`&quot;">​</a></h4><ul><li><code>path</code>: 日志目录，默认 <code>/data/log/CubeMaster</code></li><li><code>level</code>: 日志级别</li><li><code>file_size</code> / <code>file_num</code>: 单文件大小与轮转数量</li></ul><h4 id="cubelet-conf" tabindex="-1"><code>cubelet_conf</code> <a class="header-anchor" href="#cubelet-conf" aria-label="Permalink to &quot;`cubelet_conf`&quot;">​</a></h4><p>这是 Cubemaster 视角下的节点调用参数：</p><ul><li><code>grpc.grpc_port</code>: 默认访问各节点 <code>9999</code></li><li><code>create_concurrent_limit</code> / <code>destroy_concurent_limit</code>: 并发控制</li><li><code>enable_exposed_port</code>: 是否允许暴露端口</li><li><code>exposed_port_list</code>: 默认暴露端口白名单</li></ul><h4 id="auth" tabindex="-1"><code>auth</code> <a class="header-anchor" href="#auth" aria-label="Permalink to &quot;`auth`&quot;">​</a></h4><ul><li><code>enable</code>: 当前样例为 <code>false</code></li><li>如果后续接鉴权，这里是 Cubemaster 自身的开关入口之一</li></ul><h4 id="req-template-conf" tabindex="-1"><code>req_template_conf</code> <a class="header-anchor" href="#req-template-conf" aria-label="Permalink to &quot;`req_template_conf`&quot;">​</a></h4><p>定义模板请求默认值和允许透传的字段：</p><ul><li><code>whitelist_req_tag</code>: 请求白名单</li><li><code>cube_box_req_template</code>: 默认模板请求 JSON</li></ul><p>运维上要重点看这里，因为很多“新建 sandbox 默认行为”都来自这里，而不是前端。</p><h4 id="ossdb-config-instance-db-config" tabindex="-1"><code>ossdb_config</code> / <code>instance_db_config</code> <a class="header-anchor" href="#ossdb-config-instance-db-config" aria-label="Permalink to &quot;`ossdb_config` / `instance_db_config`&quot;">​</a></h4><p>MySQL 连接配置：</p><ul><li><code>addr</code>, <code>user</code>, <code>pwd</code>, <code>db_name</code></li><li><code>max_idle_conns</code>, <code>max_open_conns</code></li><li><code>max_conn_life_time_seconds</code></li></ul><h4 id="redis-redis-read-redis-write" tabindex="-1"><code>redis</code> / <code>redis_read</code> / <code>redis_write</code> <a class="header-anchor" href="#redis-redis-read-redis-write" aria-label="Permalink to &quot;`redis` / `redis_read` / `redis_write`&quot;">​</a></h4><p>Redis 连接配置：</p><ul><li><code>nodes</code></li><li><code>password</code></li><li><code>db_no</code></li><li><code>max_idle</code>, <code>max_active</code>, <code>idle_timeout</code></li></ul><h4 id="scheduler" tabindex="-1"><code>scheduler</code> <a class="header-anchor" href="#scheduler" aria-label="Permalink to &quot;`scheduler`&quot;">​</a></h4><p>控制调度策略：</p><ul><li><code>priority_select_num</code></li><li><code>metric_update_timeout</code></li><li><code>filter.enable_filters</code></li></ul><h2 id="_3-cubeapi-配置" tabindex="-1">3. CubeAPI 配置 <a class="header-anchor" href="#_3-cubeapi-配置" aria-label="Permalink to &quot;3. CubeAPI 配置&quot;">​</a></h2><h3 id="_3-1-配置来源" tabindex="-1">3.1 配置来源 <a class="header-anchor" href="#_3-1-配置来源" aria-label="Permalink to &quot;3.1 配置来源&quot;">​</a></h3><p>CubeAPI <strong>没有单独的 yaml/toml 配置文件</strong>，配置来源按优先级为：</p><ol><li>CLI flag</li><li>环境变量</li><li>内建默认值</li></ol><p>在 one-click 场景里，环境变量主要来自 <code>/usr/local/services/cubetoolbox/.one-click.env</code>。</p><h3 id="_3-2-主要环境变量-默认值" tabindex="-1">3.2 主要环境变量/默认值 <a class="header-anchor" href="#_3-2-主要环境变量-默认值" aria-label="Permalink to &quot;3.2 主要环境变量/默认值&quot;">​</a></h3><p>源码在 <code>CubeAPI/src/config/mod.rs</code>。</p><table tabindex="0"><thead><tr><th>配置项</th><th>默认值</th><th>来源</th></tr></thead><tbody><tr><td><code>CUBE_API_BIND</code></td><td><code>0.0.0.0:3000</code></td><td>HTTP 监听地址</td></tr><tr><td><code>CUBE_MASTER_ADDR</code></td><td><code>http://127.0.0.1:8089</code></td><td>Cubemaster 基地址</td></tr><tr><td><code>CUBE_API_SANDBOX_DOMAIN</code></td><td><code>cube.app</code></td><td>返回给客户端的域名</td></tr><tr><td><code>LOG_DIR</code></td><td><code>&lt;binary_dir&gt;/log</code></td><td>文件日志目录</td></tr><tr><td><code>LOG_PREFIX</code></td><td><code>cube-api</code></td><td>日志前缀</td></tr><tr><td><code>AUTH_CALLBACK_URL</code></td><td>空</td><td>外部鉴权回调</td></tr><tr><td><code>RATE_LIMIT_PER_SEC</code></td><td><code>100</code></td><td>每 API Key 限速</td></tr><tr><td><code>INSTANCE_TYPE</code></td><td><code>cubebox</code></td><td>默认实例类型</td></tr><tr><td><code>WORKER_THREADS</code></td><td><code>16</code></td><td>Tokio 线程数</td></tr><tr><td><code>LOG_LEVEL</code></td><td><code>info</code></td><td>日志等级</td></tr></tbody></table><h3 id="_3-3-one-click-启动时的实际覆盖" tabindex="-1">3.3 one-click 启动时的实际覆盖 <a class="header-anchor" href="#_3-3-one-click-启动时的实际覆盖" aria-label="Permalink to &quot;3.3 one-click 启动时的实际覆盖&quot;">​</a></h3><p><code>up.sh</code> 启动 <code>cube-api</code> 时会注入：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">LOG_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/data/log/CubeAPI</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CUBE_API_BIND</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0.0.0.0:3000</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CUBE_API_SANDBOX_DOMAIN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cube.app</span></span></code></pre></div><p>如果设置了：</p><ul><li><code>CUBE_MASTER_ADDR</code></li><li><code>AUTH_CALLBACK_URL</code></li></ul><p>也会一并注入。</p><h2 id="_4-support-mysql-redis-配置" tabindex="-1">4. support：MySQL / Redis 配置 <a class="header-anchor" href="#_4-support-mysql-redis-配置" aria-label="Permalink to &quot;4. support：MySQL / Redis 配置&quot;">​</a></h2><h3 id="_4-1-路径" tabindex="-1">4.1 路径 <a class="header-anchor" href="#_4-1-路径" aria-label="Permalink to &quot;4.1 路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>路径</th></tr></thead><tbody><tr><td>仓库模板</td><td><code>deploy/one-click/support/docker-compose.yaml.template</code></td></tr><tr><td>安装后生成</td><td><code>/usr/local/services/cubetoolbox/support/docker-compose.yaml</code></td></tr></tbody></table><h3 id="_4-2-配置说明" tabindex="-1">4.2 配置说明 <a class="header-anchor" href="#_4-2-配置说明" aria-label="Permalink to &quot;4.2 配置说明&quot;">​</a></h3><p>该 compose 模板负责启动：</p><ul><li><code>mysql:8.0</code></li><li><code>redis:7-alpine</code></li></ul><p>关键渲染项：</p><table tabindex="0"><thead><tr><th>配置</th><th>说明</th></tr></thead><tbody><tr><td><code>__MYSQL_CONTAINER__</code></td><td>MySQL 容器名</td></tr><tr><td><code>__MYSQL_DB__</code> / <code>__MYSQL_USER__</code> / <code>__MYSQL_PASSWORD__</code></td><td>业务库与用户</td></tr><tr><td><code>__MYSQL_VOLUME__</code></td><td>MySQL 数据卷</td></tr><tr><td><code>__SQL_DIR__</code></td><td>初始化 SQL 目录</td></tr><tr><td><code>__REDIS_CONTAINER__</code></td><td>Redis 容器名</td></tr><tr><td><code>__REDIS_PASSWORD__</code></td><td>Redis 密码</td></tr><tr><td><code>__REDIS_VOLUME__</code></td><td>Redis 数据卷</td></tr></tbody></table><p>运维上要关注：</p><ul><li>数据是否在 volume 中持久化</li><li>端口是否与宿主已有服务冲突</li><li>SQL 初始化脚本是否已按版本升级</li></ul><h2 id="_5-cubeproxy-配置" tabindex="-1">5. CubeProxy 配置 <a class="header-anchor" href="#_5-cubeproxy-配置" aria-label="Permalink to &quot;5. CubeProxy 配置&quot;">​</a></h2><h3 id="_5-1-路径" tabindex="-1">5.1 路径 <a class="header-anchor" href="#_5-1-路径" aria-label="Permalink to &quot;5.1 路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>路径</th></tr></thead><tbody><tr><td>模板</td><td><code>deploy/one-click/cubeproxy/global.conf.template</code></td></tr><tr><td>安装后生成</td><td><code>/usr/local/services/cubetoolbox/cubeproxy/global.conf</code></td></tr><tr><td>compose 模板</td><td><code>deploy/one-click/cubeproxy/docker-compose.yaml.template</code></td></tr><tr><td>安装后 compose</td><td><code>/usr/local/services/cubetoolbox/cubeproxy/docker-compose.yaml</code></td></tr></tbody></table><h3 id="_5-2-global-conf-关键项" tabindex="-1">5.2 <code>global.conf</code> 关键项 <a class="header-anchor" href="#_5-2-global-conf-关键项" aria-label="Permalink to &quot;5.2 `global.conf` 关键项&quot;">​</a></h3><p>模板中实际被渲染的值只有几类：</p><table tabindex="0"><thead><tr><th>变量</th><th>作用</th></tr></thead><tbody><tr><td><code>redis_ip</code> / <code>redis_port</code> / <code>redis_pd</code></td><td>CubeProxy Lua/OpenResty 访问 Redis</td></tr><tr><td><code>cube_proxy_host_ip</code></td><td>当前节点宿主机 IP</td></tr><tr><td><code>timeout_min</code> / <code>timeout_max</code></td><td>代理超时窗口</td></tr></tbody></table><h3 id="_5-3-compose-关键项" tabindex="-1">5.3 compose 关键项 <a class="header-anchor" href="#_5-3-compose-关键项" aria-label="Permalink to &quot;5.3 compose 关键项&quot;">​</a></h3><p>生成后的 compose 会：</p><ul><li>暴露宿主机 <code>443 -&gt; 容器 8080</code></li><li>暴露宿主机 <code>80 -&gt; 容器 8081</code></li><li>把证书目录只读挂载到 <code>/usr/local/openresty/nginx/certs</code></li><li>把生成后的 <code>global.conf</code> 挂载到 <code>/usr/local/openresty/nginx/conf/global/global.conf</code></li><li>使用 <code>Dockerfile.oneclick</code> 本地构建镜像</li></ul><h2 id="_6-coredns-配置" tabindex="-1">6. CoreDNS 配置 <a class="header-anchor" href="#_6-coredns-配置" aria-label="Permalink to &quot;6. CoreDNS 配置&quot;">​</a></h2><h3 id="_6-1-路径" tabindex="-1">6.1 路径 <a class="header-anchor" href="#_6-1-路径" aria-label="Permalink to &quot;6.1 路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>路径</th></tr></thead><tbody><tr><td>模板</td><td><code>deploy/one-click/coredns/Corefile.template</code></td></tr><tr><td>安装后生成</td><td><code>/usr/local/services/cubetoolbox/coredns/Corefile</code></td></tr><tr><td>生成的上游解析</td><td><code>/usr/local/services/cubetoolbox/coredns/resolv.conf.upstream</code></td></tr><tr><td>compose</td><td><code>/usr/local/services/cubetoolbox/coredns/docker-compose.yaml</code></td></tr></tbody></table><h3 id="_6-2-corefile-行为" tabindex="-1">6.2 Corefile 行为 <a class="header-anchor" href="#_6-2-corefile-行为" aria-label="Permalink to &quot;6.2 Corefile 行为&quot;">​</a></h3><p>CoreDNS 的作用非常明确：</p><ul><li>对 <code>cube.app</code> 返回固定 A 记录</li><li>对 <code>*.cube.app</code> 返回固定 A 记录</li><li>非命中域名继续使用 <code>/etc/resolv.conf</code> 转发</li></ul><p>模板逻辑：</p><ul><li><code>__CUBE_PROXY_DNS_ANSWER_IP__</code>：返回给 <code>cube.app</code> 的 IP</li><li><code>__COREDNS_BIND_ADDR__</code>：CoreDNS 实际绑定地址</li></ul><h3 id="_6-3-dns-接管状态文件" tabindex="-1">6.3 DNS 接管状态文件 <a class="header-anchor" href="#_6-3-dns-接管状态文件" aria-label="Permalink to &quot;6.3 DNS 接管状态文件&quot;">​</a></h3><p><code>up-dns.sh</code> / <code>down-dns.sh</code> 还会维护：</p><ul><li><code>/usr/local/services/cubetoolbox/coredns/host-dns-mode</code></li><li><code>/usr/local/services/cubetoolbox/coredns/host-dns-interface</code></li></ul><p>它们用于记录：</p><ul><li>当前是 <code>systemd-resolved</code> 模式还是 <code>NetworkManager + dnsmasq</code> 回退模式</li><li>使用了哪个 link/interface 做 <code>cube.app</code> 域名接管</li></ul><h2 id="_7-webui-配置" tabindex="-1">7. WebUI 配置 <a class="header-anchor" href="#_7-webui-配置" aria-label="Permalink to &quot;7. WebUI 配置&quot;">​</a></h2><h3 id="_7-1-路径" tabindex="-1">7.1 路径 <a class="header-anchor" href="#_7-1-路径" aria-label="Permalink to &quot;7.1 路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>路径</th></tr></thead><tbody><tr><td>nginx 模板</td><td><code>deploy/one-click/webui/nginx.conf</code></td></tr><tr><td>安装后生成 nginx</td><td><code>/usr/local/services/cubetoolbox/webui/nginx.generated.conf</code></td></tr><tr><td>compose 模板</td><td><code>deploy/one-click/webui/docker-compose.yaml.template</code></td></tr><tr><td>安装后 compose</td><td><code>/usr/local/services/cubetoolbox/webui/docker-compose.yaml</code></td></tr><tr><td>静态资源目录</td><td><code>/usr/local/services/cubetoolbox/webui/dist</code></td></tr></tbody></table><h3 id="_7-2-nginx-配置说明" tabindex="-1">7.2 nginx 配置说明 <a class="header-anchor" href="#_7-2-nginx-配置说明" aria-label="Permalink to &quot;7.2 nginx 配置说明&quot;">​</a></h3><p>这个 nginx 只做两件事：</p><ol><li>提供前端静态资源</li><li>把 <code>/cubeapi/</code> 反代到宿主机 CubeAPI</li></ol><p>关键 location：</p><table tabindex="0"><thead><tr><th>路径</th><th>作用</th></tr></thead><tbody><tr><td><code>/cubeapi/</code></td><td>反代到 <code>__WEB_UI_UPSTREAM__/cubeapi/</code></td></tr><tr><td><code>/assets/</code></td><td>静态资源缓存一年</td></tr><tr><td><code>/</code></td><td>SPA fallback 到 <code>index.html</code></td></tr></tbody></table><h3 id="_7-3-compose-说明" tabindex="-1">7.3 compose 说明 <a class="header-anchor" href="#_7-3-compose-说明" aria-label="Permalink to &quot;7.3 compose 说明&quot;">​</a></h3><p>生成后的 compose 会：</p><ul><li>暴露 <code>WEB_UI_HOST_PORT:80</code></li><li>通过 <code>extra_hosts</code> 把 <code>host.docker.internal</code> 映射到 <code>host-gateway</code></li><li>只读挂载 <code>dist</code> 和 <code>nginx.generated.conf</code></li><li>用 <code>wget http://127.0.0.1/</code> 做健康检查</li></ul><h2 id="_8-控制面改配置时的建议顺序" tabindex="-1">8. 控制面改配置时的建议顺序 <a class="header-anchor" href="#_8-控制面改配置时的建议顺序" aria-label="Permalink to &quot;8. 控制面改配置时的建议顺序&quot;">​</a></h2><p>如果要调整控制面行为，建议按下面顺序排查：</p><ol><li>先看 <code>.one-click.env</code> 是否覆盖了默认值</li><li>再看 <code>CubeMaster/conf.yaml</code> 中调度与存储配置</li><li>再看 <code>CubeAPI</code> 的 env / flag 是否被脚本覆盖</li><li>如果是入口域名/证书/页面问题，再看 <code>cubeproxy</code> / <code>coredns</code> / <code>webui</code></li><li>改完后运行：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./smoke.sh</span></span></code></pre></div><p>或直接执行安装后的：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/local/services/cubetoolbox/scripts/one-click/quickcheck.sh</span></span></code></pre></div>',108)])])}const u=d(a,[["render",l]]);export{_ as __pageData,u as default};
